(function(){if(window.btdt&&window.btdt._initialized)return;const script=document.currentScript;if(!script)return;const detectedBase=script.src.split('/').slice(0,-2).join('/')+'/';const basePath=(script.getAttribute('data-base-path')||detectedBase).replace(/\/?$/,'/');const autoInit=script.getAttribute('data-auto-init')!=='false';const initialPreset=script.getAttribute('data-preset');const initialMode=script.getAttribute('data-mode');const defaultMinified=script.getAttribute('data-minified')==='true';function withCacheBust(path){const sep=path.includes('?')?'&':'?';return`${path}${sep}v=${Date.now()}`;}
function getOrCreateLink(id,href,disabled){let link=document.getElementById(id);if(!link){link=document.createElement('link');link.id=id;link.rel='stylesheet';document.head.appendChild(link);}
if(typeof disabled==='boolean'){link.disabled=disabled;}
if(href){link.href=withCacheBust(href);}
return link;}
function findPresetLink(){return document.getElementById('theme-preset')||Array.from(document.querySelectorAll('link[rel="stylesheet"]')).find((link)=>link.href.includes('/themes/preset/')||link.href.includes('themes/preset/'))||null;}
function resolvePresetHref(name,options){const useMinified=Boolean(options&&options.minified);if(!name)return null;if(name.endsWith('.css')||name.includes('/'))return name;return`${basePath}themes/preset/${name}${useMinified ? '.min' : ''}.css`;}
function ensurePresetLink(){const existing=findPresetLink();if(existing){existing.id='theme-preset';return existing;}
return getOrCreateLink('theme-preset');}
function ensureModeLink(){return getOrCreateLink('theme-mode',`${basePath}themes/modes/dark.css`,true);}
function applyMode(mode){const normalized=mode==='dark'?'dark':'light';const modeLink=ensureModeLink();document.documentElement.setAttribute('data-bs-theme',normalized);if(normalized==='dark'){document.documentElement.setAttribute('data-mode','dark');modeLink.disabled=false;}else{document.documentElement.removeAttribute('data-mode');modeLink.disabled=true;}
document.head.appendChild(modeLink);return normalized;}
window.btdt={_initialized:true,_mode:document.documentElement.getAttribute('data-bs-theme')==='dark'?'dark':'light',load:function(name,options){const normalizedOptions={minified:defaultMinified,...(options||{})};const href=resolvePresetHref(name,normalizedOptions);if(!href)return this;const link=ensurePresetLink();link.href=withCacheBust(href);document.head.appendChild(link);return this;},setMode:function(mode){this._mode=applyMode(mode);return this;},toggleMode:function(){return this.setMode(this._mode==='dark'?'light':'dark');},getMode:function(){return this._mode;}};if(autoInit){ensureModeLink();if(initialPreset){window.btdt.load(initialPreset);}else{const existingPreset=findPresetLink();if(existingPreset)existingPreset.id='theme-preset';}
if(initialMode==='dark'||initialMode==='light'){window.btdt.setMode(initialMode);}else{window.btdt.setMode(window.btdt._mode);}}})();